import React, { useState } from 'react';

const rooms = [
  {
    name: 'Garden Villa',
    type: 'Standard',
    price: '$280',
    img: 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=700&q=80&auto=format',
    desc: 'A serene retreat nestled among tropical gardens with a private terrace.',
    features: ['Free WiFi', 'Air Conditioning', 'King Bed', 'Garden View', 'Room Service'],
    size: '42 m²',
    guests: '2',
  },
  {
    name: 'Ocean Deluxe',
    type: 'Deluxe',
    price: '$480',
    img: 'https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=700&q=80&auto=format',
    desc: 'Wake up to panoramic ocean views from your elegant suite with a plunge pool.',
    features: ['Free WiFi', 'Air Conditioning', 'Plunge Pool', 'Ocean View', 'Mini Bar', 'Butler Service'],
    size: '68 m²',
    guests: '2',
    badge: 'Popular',
  },
  {
    name: 'Overwater Suite',
    type: 'Suite',
    price: '$850',
    img: 'https://images.unsplash.com/photo-1602002418082-a4443e081dd1?w=700&q=80&auto=format',
    desc: 'The ultimate indulgence — a glass-floor suite suspended above crystal-clear lagoon waters.',
    features: ['Free WiFi', 'Air Conditioning', 'Private Pool', 'Glass Floor', 'Pool Access', 'Butler Service', 'Sea Plane Transfer'],
    size: '120 m²',
    guests: '2–4',
    badge: 'Exclusive',
  },
  {
    name: 'Family Bungalow',
    type: 'Family',
    price: '$560',
    img: 'https://images.unsplash.com/photo-1596394516093-501ba68a0ba6?w=700&q=80&auto=format',
    desc: 'Spacious beachfront bungalow designed for families with separate living and sleeping areas.',
    features: ['Free WiFi', 'Air Conditioning', 'Pool Access', 'Beach Access', 'Kids Club', '2 Bathrooms'],
    size: '95 m²',
    guests: '2–5',
  },
];

const Rooms = () => {
  const [active, setActive] = useState(null);

  return (
    <>
      {/* CSS */}
      <style>{`
        .rooms {
          padding: 100px 0;
          background: var(--deep-teal);
          position: relative;
          overflow: hidden;
        }

        .rooms__bg-text {
          position: absolute;
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%);
          font-size: clamp(6rem, 15vw, 14rem);
          color: rgba(255,255,255,0.03);
        }

        .rooms__grid {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 24px;
        }

        .room-card {
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.08);
          transition: 0.3s;
        }

        .room-card:hover {
          transform: translateY(-4px);
        }

        .room-card__img-wrap img {
          width: 100%;
          height: 260px;
          object-fit: cover;
        }

        .room-card__body {
          padding: 24px;
        }

        .room-card__name {
          font-size: 1.5rem;
          color: white;
        }

        .room-card__desc {
          color: rgba(255,255,255,0.6);
        }

        .room-card__footer {
          display: flex;
          justify-content: space-between;
          margin-top: 20px;
        }

        @media (max-width: 768px) {
          .rooms__grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>

      {/* JSX */}
      <section id="rooms" className="rooms">
        <div className="rooms__bg-text">ROOMS</div>

        <div className="container">
          <div className="rooms__header">
            <h2>Find Your Perfect Retreat</h2>
          </div>

          <div className="rooms__grid">
            {rooms.map((room, i) => (
              <div
                key={i}
                className="room-card"
                onMouseEnter={() => setActive(i)}
                onMouseLeave={() => setActive(null)}
              >
                <div className="room-card__img-wrap">
                  <img src={room.img} alt={room.name} />
                </div>

                <div className="room-card__body">
                  <h3 className="room-card__name">{room.name}</h3>
                  <p className="room-card__desc">{room.desc}</p>

                  <div className="room-card__footer">
                    <span>{room.price}</span>
                    <button
                      onClick={() =>
                        document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' })
                      }
                    >
                      Book
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
};

export default Rooms;
